 /**
  * Extract the notification category from a NotificationType.
  * e.g., 'order:confirmation' → 'order', 'user:welcome' → 'user'
@@ -118,3 +154,37 @@ export const defaultEmailPreferences: EmailPreferences = {
 export function getCategoryFromType(type: NotificationType): NotificationCategory {
   return type.split(':')[0] as NotificationCategory;
 }
+
+/**
+ * Channel-aware check: should a notification be sent on a given channel?
+ * Used by PreferencesService to avoid duplicating logic per channel.
+ *
+ * For email, also checks frequency ('none' suppresses).
+ * For SMS and webhook, only checks enabled + category.
+ */
+export function shouldNotifyForChannel(
+  channel: NotificationChannel,
+  prefs: UserPreferences,
+  type: NotificationType,
+): boolean {
+  const category = getCategoryFromType(type);
+
+  if (channel === 'email') {
+    if (!prefs.email.enabled) return false;
+    if (prefs.email.frequency === 'none') return false;
+    return prefs.email.categories[category] !== false;
+  }
+
+  if (channel === 'sms') {
+    if (!prefs.sms.enabled) return false;
+    return prefs.sms.categories[category] !== false;
+  }
+
+  if (channel === 'webhook') {
+    if (!prefs.webhook.enabled) return false;
+    return prefs.webhook.categories[category] !== false;
+  }
+
+  // Unknown channel or 'in-app' — send by default
+  return true;
+}

