parameters.content:
/**
 * User notification preferences model — multi-channel.
 *
 * Controls how and when a user receives notifications across all channels
 * (email, SMS, webhook).
 *
 * ## Decision Change (Agent 9)
 * This model was originally email-only (Agent 3). With SMS added (Agent 8)
 * and webhook already available (Agent 6), we've refactored to support
 * per-channel preferences. The email-only assumption is no longer valid.
 *
 * Changes from the original email-only model:
 * - Added `SmsPreferences` and `WebhookPreferences` interfaces
 * - `UserPreferences` now has `sms` and `webhook` fields alongside `email`
 * - `UpdatePreferencesInput` accepts `sms` and `webhook` fields
 * - Added `defaultSmsPreferences` and `defaultWebhookPreferences`
 * - Added `shouldNotify(channel, prefs, type)` utility for channel-aware checks
 *
 * Backward compatibility:
 * - Existing `email` field and `EmailPreferences` interface are unchanged
 * - `defaultEmailPreferences` is unchanged
 * - `getCategoryFromType()` is unchanged
 * - Preferences records without `sms`/`webhook` fields are treated as defaults
 *   (opt-out model: send by default)
 *
 * Design decisions:
 * - Opt-out model: users receive all notifications by default on all channels.
 * - Categories map to the prefix of NotificationType (e.g., 'order', 'user').
 * - Email has `frequency` for batching; SMS and webhook do not (always immediate).
 */

import type { NotificationChannel, NotificationType } from './notification.js';

/**
 * High-level notification categories derived from NotificationType prefixes.
 * 'order' covers order:confirmation and order:status-update.
 * 'user' covers user:welcome and user:profile-updated.
 */
export type NotificationCategory = 'order' | 'user';

/**
 * Email delivery frequency.
 * - 'immediate': send as soon as the event occurs
 * - 'daily-digest': batch into a daily summary (future implementation)
 * - 'none': do not send email notifications
 */
export type EmailFrequency = 'immediate' | 'daily-digest' | 'none';

/**
 * Email-specific notification preferences.
 */
export interface EmailPreferences {
  /** Global email on/off switch. When false, no emails are sent. */
  enabled: boolean;
  /** How often to deliver email notifications. */
  frequency: EmailFrequency;
  /** Per-category opt-in/out. True means subscribed. */
  categories: Record<NotificationCategory, boolean>;
}

/**
 * SMS-specific notification preferences.
 * SMS is always immediate — no frequency/digest batching.
 */
export interface SmsPreferences {
  /** Global SMS on/off switch. When false, no SMS messages are sent. */
  enabled: boolean;
  /** Per-category opt-in/out. True means subscribed. */
  categories: Record<NotificationCategory, boolean>;
}

/**
 * Webhook-specific notification preferences.
 * Webhooks are always immediate — no frequency/digest batching.
 */
export interface WebhookPreferences {
  /** Global webhook on/off switch. When false, no webhooks are sent. */
  enabled: boolean;
  /** Per-category opt-in/out. True means subscribed. */
  categories: Record<NotificationCategory, boolean>;
}

/**
 * Complete notification preferences for a user.
 * One preferences record per user (1:1 relationship).
 */
export interface UserPreferences {
  id: string;
  userId: string;
  email: EmailPreferences;
  sms: SmsPreferences;
  webhook: WebhookPreferences;
  updatedAt: Date;
}

/**
 * Input for updating a user's notification preferences.
 * All fields are optional — only provided fields are updated.
 */
export interface UpdatePreferencesInput {
  email?: {
    enabled?: boolean;
    frequency?: EmailFrequency;
    categories?: Partial<Record<NotificationCategory, boolean>>;
  };
  sms?: {
    enabled?: boolean;
    categories?: Partial<Record<NotificationCategory, boolean>>;
  };
  webhook?: {
    enabled?: boolean;
    categories?: Partial<Record<NotificationCategory, boolean>>;
  };
}

/**
 * Default email preferences for new users (opt-out model: everything enabled).
 */
export const defaultEmailPreferences: EmailPreferences = {
  enabled: true,
  frequency: 'immediate',
  categories: {
    order: true,
    user: true,
  },
};

/**
 * Default SMS preferences for new users (opt-out model: everything enabled).
 */
export const defaultSmsPreferences: SmsPreferences = {
  enabled: true,
  categories: {
    order: true,
    user: true,
  },
};

/**
 * Default webhook preferences for new users (opt-out model: everything enabled).
 */
export const defaultWebhookPreferences: WebhookPreferences = {
  enabled: true,
  categories: {
    order: true,
    user: true,
  },
};

/**
 * Extract the notification category from a NotificationType.
 * e.g., 'order:confirmation' → 'order', 'user:welcome' → 'user'
 */
export function getCategoryFromType(type: NotificationType): NotificationCategory {
  return type.split(':')[0] as NotificationCategory;
}

/**
 * Channel-aware check: should a notification be sent on a given channel?
 * Used by PreferencesService to avoid duplicating logic per channel.
 *
 * For email, also checks frequency ('none' suppresses).
 * For SMS and webhook, only checks enabled + category.
 */
export function shouldNotifyForChannel(
  channel: NotificationChannel,
  prefs: UserPreferences,
  type: NotificationType,
): boolean {
  const category = getCategoryFromType(type);

  if (channel === 'email') {
    if (!prefs.email.enabled) return false;
    if (prefs.email.frequency === 'none') return false;
    return prefs.email.categories[category] !== false;
  }

  if (channel === 'sms') {
    if (!prefs.sms.enabled) return false;
    return prefs.sms.categories[category] !== false;
  }

  if (channel === 'webhook') {
    if (!prefs.webhook.enabled) return false;
    return prefs.webhook.categories[category] !== false;
  }

  // Unknown channel or 'in-app' — send by default
  return true;
}

/**
 * Repository for UserPreferences data access.
 *
 * Extends BaseRepository with preferences-specific query methods.
 * Each user has at most one preferences record (1:1 relationship).
 *
 * Supports multi-channel preferences (email, SMS, webhook).
 * Backward compatible: records missing sms/webhook fields get defaults on read.
 */

import type { DatabaseRecord } from '../utils/database.js';
import type { Database } from '../utils/database.js';
import type {
  UserPreferences,
  EmailPreferences,
  SmsPreferences,
  WebhookPreferences,
  NotificationCategory,
} from '../models/user-preferences.js';
import { defaultSmsPreferences, defaultWebhookPreferences } from '../models/user-preferences.js';
import { BaseRepository } from './base.repository.js';

export class PreferencesRepository extends BaseRepository<UserPreferences> {
  constructor(db: Database) {
    super(db, 'user-preferences');
  }

  protected toDomain(record: DatabaseRecord): UserPreferences {
    const emailCategories = JSON.parse(record['emailCategories'] as string) as Record<NotificationCategory, boolean>;

    // Backward compatible: default SMS/webhook prefs if not in record
    const smsCategories = record['smsCategories']
      ? JSON.parse(record['smsCategories'] as string) as Record<NotificationCategory, boolean>
      : { ...defaultSmsPreferences.categories };

    const webhookCategories = record['webhookCategories']
      ? JSON.parse(record['webhookCategories'] as string) as Record<NotificationCategory, boolean>
      : { ...defaultWebhookPreferences.categories };

    return {
      id: record['id'] as string,
      userId: record['userId'] as string,
      email: {
        enabled: record['emailEnabled'] as boolean,
        frequency: record['emailFrequency'] as EmailPreferences['frequency'],
        categories: emailCategories,
      },
      sms: {
        enabled: record['smsEnabled'] !== undefined ? record['smsEnabled'] as boolean : defaultSmsPreferences.enabled,
        categories: smsCategories,
      },
      webhook: {
        enabled: record['webhookEnabled'] !== undefined ? record['webhookEnabled'] as boolean : defaultWebhookPreferences.enabled,
        categories: webhookCategories,
      },
      updatedAt: new Date(record['updatedAt'] as string),
    };
  }

  protected toRecord(entity: UserPreferences): DatabaseRecord {
    return {
      id: entity.id,
      userId: entity.userId,
      emailEnabled: entity.email.enabled,
      emailFrequency: entity.email.frequency,
      emailCategories: JSON.stringify(entity.email.categories),
      smsEnabled: entity.sms.enabled,
      smsCategories: JSON.stringify(entity.sms.categories),
      webhookEnabled: entity.webhook.enabled,
      webhookCategories: JSON.stringify(entity.webhook.categories),
      updatedAt: entity.updatedAt.toISOString(),
    };
  }

  /**
   * Find preferences by user ID.
   */
  findByUserId(userId: string): UserPreferences | undefined {
    const results = this.findAll((prefs) => prefs.userId === userId);
    return results[0];
  }
}

/**
 * Preferences service — business logic for managing user notification preferences.
 *
 * Supports multi-channel preferences (email, SMS, webhook).
 *
 * Depends on:
 * - PreferencesRepository for persistence
 * - UserRepository for validating that the user exists
 *
 * Design:
 * - Opt-out model: if no preferences record exists, the user gets all notifications.
 * - Preferences are created lazily via getOrCreatePreferences().
 * - shouldSendEmail(), shouldSendSms(), shouldSendWebhook(), and the generic
 *   shouldSend(channel, userId, type) are the main queries used by
 *   NotificationService to decide whether to deliver a notification.
 */

import type { NotificationChannel, NotificationType } from '../models/notification.js';
import type {
  UserPreferences,
  UpdatePreferencesInput,
} from '../models/user-preferences.js';
import {
  defaultEmailPreferences,
  defaultSmsPreferences,
  defaultWebhookPreferences,
  shouldNotifyForChannel,
} from '../models/user-preferences.js';
import type { PreferencesRepository } from '../repositories/preferences.repository.js';
import type { UserRepository } from '../repositories/user.repository.js';
import { Logger } from '../utils/logger.js';

let nextId = 1;

function generatePreferencesId(): string {
  return `pref-${String(nextId++).padStart(4, '0')}`;
}

/** Reset the ID counter. Useful for testing. */
export function resetPreferencesIdCounter(): void {
  nextId = 1;
}

export class PreferencesService {
  private logger = new Logger('PreferencesService');

  constructor(
    private preferencesRepository: PreferencesRepository,
    private userRepository: UserRepository,
  ) {}

  /**
   * Get preferences for a user. Returns undefined if no preferences have
   * been set (caller should treat this as "use defaults").
   */
  getPreferences(userId: string): UserPreferences | undefined {
    return this.preferencesRepository.findByUserId(userId);
  }

  /**
   * Get preferences for a user, creating default preferences if none exist.
   * Validates that the user exists before creating.
   */
  getOrCreatePreferences(userId: string): UserPreferences {
    const existing = this.preferencesRepository.findByUserId(userId);
    if (existing) {
      return existing;
    }

    const user = this.userRepository.findById(userId);
    if (!user) {
      throw new Error(`User not found: ${userId}`);
    }

    const prefs: UserPreferences = {
      id: generatePreferencesId(),
      userId,
      email: { ...defaultEmailPreferences, categories: { ...defaultEmailPreferences.categories } },
      sms: { ...defaultSmsPreferences, categories: { ...defaultSmsPreferences.categories } },
      webhook: { ...defaultWebhookPreferences, categories: { ...defaultWebhookPreferences.categories } },
      updatedAt: new Date(),
    };

    this.preferencesRepository.save(prefs);
    this.logger.info(`Created default preferences for user ${userId}`);
    return prefs;
  }

  /**
   * Update a user's notification preferences.
   * Creates default preferences first if none exist, then applies updates.
   */
  updatePreferences(userId: string, input: UpdatePreferencesInput): UserPreferences {
    const current = this.getOrCreatePreferences(userId);

    const updatedEmail = { ...current.email };
    if (input.email) {
      if (input.email.enabled !== undefined) {
        updatedEmail.enabled = input.email.enabled;
      }
      if (input.email.frequency !== undefined) {
        updatedEmail.frequency = input.email.frequency;
      }
      if (input.email.categories) {
        updatedEmail.categories = {
          ...updatedEmail.categories,
          ...input.email.categories,
        };
      }
    }

    const updatedSms = { ...current.sms };
    if (input.sms) {
      if (input.sms.enabled !== undefined) {
        updatedSms.enabled = input.sms.enabled;
      }
      if (input.sms.categories) {
        updatedSms.categories = {
          ...updatedSms.categories,
          ...input.sms.categories,
        };
      }
    }

    const updatedWebhook = { ...current.webhook };
    if (input.webhook) {
      if (input.webhook.enabled !== undefined) {
        updatedWebhook.enabled = input.webhook.enabled;
      }
      if (input.webhook.categories) {
        updatedWebhook.categories = {
          ...updatedWebhook.categories,
          ...input.webhook.categories,
        };
      }
    }

    const updated = this.preferencesRepository.update(current.id, {
      email: updatedEmail,
      sms: updatedSms,
      webhook: updatedWebhook,
      updatedAt: new Date(),
    });

    this.logger.info(`Updated preferences for user ${userId}`);
    return updated;
  }

  /**
   * Check whether an email notification should be sent for a given user
   * and notification type, based on the user's preferences.
   *
   * Returns true if:
   * - The user has no preferences (opt-out model: send by default)
   * - Email is globally enabled AND the notification's category is enabled
   *   AND frequency is not 'none'
   */
  shouldSendEmail(userId: string, type: NotificationType): boolean {
    return this.shouldSend('email', userId, type);
  }

  /**
   * Check whether an SMS notification should be sent for a given user
   * and notification type, based on the user's preferences.
   */
  shouldSendSms(userId: string, type: NotificationType): boolean {
    return this.shouldSend('sms', userId, type);
  }

  /**
   * Check whether a webhook notification should be sent for a given user
   * and notification type, based on the user's preferences.
   */
  shouldSendWebhook(userId: string, type: NotificationType): boolean {
    return this.shouldSend('webhook', userId, type);
  }

  /**
   * Generic channel-aware preference check.
   * Returns true if the notification should be sent on the given channel.
   *
   * No preferences = send by default (opt-out model).
   */
  shouldSend(channel: NotificationChannel, userId: string, type: NotificationType): boolean {
    const prefs = this.preferencesRepository.findByUserId(userId);

    // No preferences = send by default (opt-out model)
    if (!prefs) {
      return true;
    }

    return shouldNotifyForChannel(channel, prefs, type);
  }
}

/**
 * Notification service — orchestrates notification delivery in response to
 * domain events received via the EventBus.
 *
 * Architecture:
 * - Subscribes to domain events exclusively through EventBus (no CallbackRegistry).
 * - Translates domain events into NotificationPayloads.
 * - Dispatches payloads to registered NotificationAdapters by channel.
 * - Checks per-channel user preferences before sending.
 * - Maintains an in-memory log of all sent notifications.
 *
 * Multi-channel support (Agent 9):
 * - Event handlers now dispatch to all configured channels (email, SMS, webhook).
 * - Preference checks are channel-aware via PreferencesService.shouldSend().
 * - SMS dispatch requires User.phone; if absent, SMS is skipped for that user.
 *
 * Constraints:
 * - ALL notifications MUST go through EventBus.emit() → NotificationService → Adapter.
 * - Services MUST NOT send notifications directly; they emit domain events instead.
 * - Each NotificationAdapter handles exactly one channel (email, webhook, etc.).
 * - Register adapters via registerAdapter() before events are emitted.
 *
 * Depends on:
 * - EventBus for receiving domain events
 * - NotificationAdapter implementations for delivery
 * - PreferencesService (optional) for per-channel user preferences
 * - UserRepository (optional) for looking up user data (phone, email) when
 *   not available directly from the event
 */

import type { EventBus } from '../events/event-bus.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../events/event-types.js';
import type { NotificationAdapter } from '../adapters/notification.adapter.js';
import type {
  NotificationChannel,
  NotificationPayload,
  NotificationRecord,
} from '../models/notification.js';
import type { PreferencesService } from './preferences.service.js';
import type { NotificationHistoryService } from './notification-history.service.js';
import type { UserRepository } from '../repositories/user.repository.js';
import { Logger } from '../utils/logger.js';

let nextId = 1;

function generateNotificationId(): string {
  return `notif-${String(nextId++).padStart(4, '0')}`;
}

/** Reset the ID counter. Useful for testing. */
export function resetNotificationIdCounter(): void {
  nextId = 1;
}

export class NotificationService {
  private logger = new Logger('NotificationService');
  private notifications: NotificationRecord[] = [];
  private adapters: Map<NotificationChannel, NotificationAdapter> = new Map();
  private preferencesService: PreferencesService | undefined;
  private historyService: NotificationHistoryService | undefined;
  private userRepository: UserRepository | undefined;

  constructor(private eventBus: EventBus) {
    this.registerEventHandlers();
  }

  /**
   * Set the preferences service for checking user notification preferences.
   * When set, the notification service will consult user preferences before
   * sending notifications. When not set, all notifications are sent (backwards compatible).
   */
  setPreferencesService(preferencesService: PreferencesService): void {
    this.preferencesService = preferencesService;
    this.logger.info('Preferences service registered');
  }

  /**
   * Set the history service for logging notification delivery attempts.
   * When set, every notification (sent, failed, or suppressed) is logged.
   * When not set, no history is recorded (backwards compatible).
   */
  setHistoryService(historyService: NotificationHistoryService): void {
    this.historyService = historyService;
    this.logger.info('History service registered');
  }

  /**
   * Set the user repository for looking up user data (phone, email) during
   * multi-channel dispatch when the event doesn't include the full user object.
   * Optional — when not set, SMS dispatch is only possible for events that
   * include the full user object.
   */
  setUserRepository(userRepository: UserRepository): void {
    this.userRepository = userRepository;
    this.logger.info('User repository registered');
  }

  /**
   * Register a notification adapter for a given channel.
   * Only one adapter per channel is allowed; later registrations replace earlier ones.
   */
  registerAdapter(adapter: NotificationAdapter): void {
    this.logger.info(`Registered adapter for channel: ${adapter.channel}`);
    this.adapters.set(adapter.channel, adapter);
  }

  /**
   * Subscribe to all domain events that trigger notifications.
   * All subscriptions go through EventBus — no other event mechanism is used.
   */
  private registerEventHandlers(): void {
    this.eventBus.on<OrderCreatedEvent>('order:created', (event) => {
      return this.handleOrderCreated(event);
    });

    this.eventBus.on<OrderStatusChangedEvent>('order:status-changed', (event) => {
      return this.handleOrderStatusChanged(event);
    });
  }

  /**
   * Handle order created — send confirmation notification to the user
   * on all configured channels.
   */
  private async handleOrderCreated(event: OrderCreatedEvent): Promise<void> {
    this.logger.info(`Sending order confirmation for order ${event.order.id}`);

    const itemSummary = event.order.items
      .map((item) => `${item.name} x${item.quantity}`)
      .join(', ');

    const subject = `Order Confirmation: ${event.order.id}`;
    const body = `Your order has been placed. Items: ${itemSummary}. Total: $${event.order.total.toFixed(2)}`;
    const userId = event.user.id;

    // Email
    await this.sendNotification(
      {
        recipient: event.user.email,
        subject,
        body,
        channel: 'email',
        type: 'order:confirmation',
      },
      userId,
    );

    // SMS — only if user has a phone number
    if (event.user.phone) {
      await this.sendNotification(
        {
          recipient: event.user.phone,
          subject,
          body,
          channel: 'sms',
          type: 'order:confirmation',
        },
        userId,
      );
    }

    // Webhook
    await this.sendNotification(
      {
        recipient: event.user.email,
        subject,
        body,
        channel: 'webhook',
        type: 'order:confirmation',
      },
      userId,
    );
  }

  /**
   * Handle order status change — notify user of the update on all configured channels.
   */
  private async handleOrderStatusChanged(event: OrderStatusChangedEvent): Promise<void> {
    this.logger.info(
      `Sending status update for order ${event.order.id}: ${event.previousStatus} -> ${event.newStatus}`,
    );

    const subject = `Order Update: ${event.order.id}`;
    const body = `Your order status has changed from ${event.previousStatus} to ${event.newStatus}.`;
    const userId = event.order.userId;

    // Email
    await this.sendNotification(
      {
        recipient: userId,
        subject,
        body,
        channel: 'email',
        type: 'order:status-update',
      },
      userId,
    );

    // SMS — look up user for phone number
    const user = this.userRepository?.findById(userId);
    if (user?.phone) {
      await this.sendNotification(
        {
          recipient: user.phone,
          subject,
          body,
          channel: 'sms',
          type: 'order:status-update',
        },
        userId,
      );
    }

    // Webhook
    await this.sendNotification(
      {
        recipient: userId,
        subject,
        body,
        channel: 'webhook',
        type: 'order:status-update',
      },
      userId,
    );
  }

  /**
   * Send a notification: check user preferences, dispatch to the appropriate
   * adapter, and record it.
   *
   * Channel-aware preference checks: if a PreferencesService is registered,
   * the user's per-channel preferences are checked before sending.
   * Suppressed notifications are logged but not recorded or dispatched.
   * If no PreferencesService is set, all notifications are sent (backwards compatible).
   */
  private async sendNotification(payload: NotificationPayload, userId?: string): Promise<void> {
    // Check user preferences if a preferences service is available (channel-aware)
    if (this.preferencesService && userId) {
      if (!this.preferencesService.shouldSend(payload.channel, userId, payload.type)) {
        this.logger.info(
          `Notification suppressed by user preferences: ${payload.channel}/${payload.type} to ${payload.recipient}`,
        );
        await this.historyService?.log(payload, 'suppressed');
        return;
      }
    }

    const record: NotificationRecord = {
      id: generateNotificationId(),
      recipient: payload.recipient,
      subject: payload.subject,
      body: payload.body,
      channel: payload.channel,
      type: payload.type,
      sentAt: new Date(),
      metadata: payload.metadata,
    };
    this.notifications.push(record);

    const adapter = this.adapters.get(payload.channel);
    if (adapter) {
      try {
        await adapter.send(payload);
        await this.historyService?.log(payload, 'sent');
      } catch (error) {
        const errorMessage = error instanceof Error ? error.message : String(error);
        this.logger.error(
          `Adapter failed for channel ${payload.channel}: ${errorMessage}`,
        );
        await this.historyService?.log(payload, 'failed', errorMessage);
      }
    } else {
      this.logger.warn(`No adapter registered for channel: ${payload.channel}`);
      await this.historyService?.log(payload, 'sent');
    }

    this.logger.info(`Notification sent: ${record.id} to ${payload.recipient}`);
  }

  /**
   * Get all sent notifications.
   */
  getNotifications(): NotificationRecord[] {
    return [...this.notifications];
  }

  /**
   * Get notifications for a specific recipient.
   */
  getNotificationsForRecipient(recipient: string): NotificationRecord[] {
    return this.notifications.filter((n) => n.recipient === recipient);
  }

  /**
   * Get the count of sent notifications.
   */
  getNotificationCount(): number {
    return this.notifications.length;
  }

  /**
   * Clear all notifications (useful for testing).
   */
  clearNotifications(): void {
    this.notifications = [];
  }
}

