import { describe, it, expect, beforeEach } from 'vitest';
import { EventBus } from '../../src/events/event-bus.js';
import {
  NotificationService,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import { EmailAdapter } from '../../src/adapters/email.adapter.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../../src/events/event-types.js';

describe('NotificationService', () => {
  let eventBus: EventBus;
  let service: NotificationService;
  let emailAdapter: EmailAdapter;

  beforeEach(() => {
    eventBus = new EventBus();
    service = new NotificationService(eventBus);
    emailAdapter = new EmailAdapter();
    service.registerAdapter(emailAdapter);
    resetNotificationIdCounter();
  });

  describe('order:created handler', () => {
    it('should send notification on order created', async () => {
      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [
            { productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 },
          ],
          total: 20,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      // Multi-channel: email + webhook (no phone = no SMS)
      const notifications = service.getNotifications();
      expect(notifications).toHaveLength(2);

      const emailNotif = notifications.find((n) => n.channel === 'email');
      expect(emailNotif).toBeDefined();
      expect(emailNotif?.recipient).toBe('alice@example.com');
      expect(emailNotif?.subject).toContain('Order Confirmation');
      expect(emailNotif?.body).toContain('Widget x2');
      expect(emailNotif?.body).toContain('$20.00');
      expect(emailNotif?.type).toBe('order:confirmation');

      const webhookNotif = notifications.find((n) => n.channel === 'webhook');
      expect(webhookNotif).toBeDefined();
      expect(webhookNotif?.type).toBe('order:confirmation');
    });

    it('should include all items in notification body', async () => {
      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [
            { productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 },
            { productId: 'p2', name: 'Gadget', quantity: 1, unitPrice: 25 },
          ],
          total: 45,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const emailNotif = service.getNotifications().find((n) => n.channel === 'email');
      expect(emailNotif?.body).toContain('Widget x2');
      expect(emailNotif?.body).toContain('Gadget x1');
    });

    it('should also send SMS when user has phone number', async () => {
      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [
            { productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 },
          ],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          phone: '+15551234567',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      // email + SMS + webhook = 3 notifications
      const notifications = service.getNotifications();
      expect(notifications).toHaveLength(3);

      const smsNotif = notifications.find((n) => n.channel === 'sms');
      expect(smsNotif).toBeDefined();
      expect(smsNotif?.recipient).toBe('+15551234567');
      expect(smsNotif?.type).toBe('order:confirmation');
    });
  });

  describe('order:status-changed handler', () => {
    it('should send notification on status change via EventBus', async () => {
      const event: OrderStatusChangedEvent = {
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      // Multi-channel: email + webhook (no userRepository = no SMS)
      const notifications = service.getNotifications();
      expect(notifications).toHaveLength(2);

      const emailNotif = notifications.find((n) => n.channel === 'email');
      expect(emailNotif).toBeDefined();
      expect(emailNotif?.subject).toContain('Order Update');
      expect(emailNotif?.body).toContain('pending');
      expect(emailNotif?.body).toContain('confirmed');
      expect(emailNotif?.type).toBe('order:status-update');

      const webhookNotif = notifications.find((n) => n.channel === 'webhook');
      expect(webhookNotif).toBeDefined();
      expect(webhookNotif?.type).toBe('order:status-update');
    });
  });

  describe('adapter integration', () => {
    it('should dispatch to email adapter on notification', async () => {
      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [
            { productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 },
          ],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const sentEmails = emailAdapter.getSentEmails();
      expect(sentEmails).toHaveLength(1);
      expect(sentEmails[0]?.to).toBe('alice@example.com');
      expect(sentEmails[0]?.from).toBe('noreply@taskflowpro.com');
    });

    it('should still record notification when no adapter is registered', async () => {
      const localBus = new EventBus();
      const bareService = new NotificationService(localBus);
      // No adapter registered

      const event: OrderStatusChangedEvent = {
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      };

      await localBus.emit(event);

      // Multi-channel: email + webhook = 2 records even without adapters
      expect(bareService.getNotificationCount()).toBe(2);
    });
  });

  describe('notification management', () => {
    it('should count notifications', async () => {
      expect(service.getNotificationCount()).toBe(0);

      await eventBus.emit({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      });

      // email + webhook = 2
      expect(service.getNotificationCount()).toBe(2);
    });

    it('should filter by recipient', async () => {
      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [
            { productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 },
          ],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      // Both email and webhook have recipient alice@example.com
      expect(service.getNotificationsForRecipient('alice@example.com')).toHaveLength(2);
      expect(service.getNotificationsForRecipient('bob@example.com')).toHaveLength(0);
    });

    it('should clear notifications', async () => {
      await eventBus.emit({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      });

      service.clearNotifications();
      expect(service.getNotificationCount()).toBe(0);
    });

    it('should generate sequential notification IDs', async () => {
      await eventBus.emit({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      });

      const notifications = service.getNotifications();
      // email gets notif-0001, webhook gets notif-0002
      expect(notifications[0]?.id).toBe('notif-0001');
      expect(notifications[1]?.id).toBe('notif-0002');
    });
  });
});

import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { UserRepository } from '../../src/repositories/user.repository.js';
import { PreferencesRepository } from '../../src/repositories/preferences.repository.js';
import {
  PreferencesService,
  resetPreferencesIdCounter,
} from '../../src/services/preferences.service.js';
import { EventBus } from '../../src/events/event-bus.js';
import {
  NotificationService,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import { EmailAdapter } from '../../src/adapters/email.adapter.js';
import { SmsAdapter } from '../../src/adapters/sms.adapter.js';
import type { User } from '../../src/models/user.js';
import type { OrderCreatedEvent } from '../../src/events/event-types.js';

function createTestUser(db: Database, overrides: Partial<User> = {}): User {
  const user: User = {
    id: 'user-0001',
    name: 'Alice',
    email: 'alice@example.com',
    role: 'member',
    createdAt: new Date(),
    updatedAt: new Date(),
    ...overrides,
  };
  const userRepo = new UserRepository(db);
  userRepo.save(user);
  return user;
}

describe('PreferencesService', () => {
  let db: Database;
  let userRepo: UserRepository;
  let prefsRepo: PreferencesRepository;
  let service: PreferencesService;

  beforeEach(() => {
    db = new Database();
    userRepo = new UserRepository(db);
    prefsRepo = new PreferencesRepository(db);
    service = new PreferencesService(prefsRepo, userRepo);
    resetPreferencesIdCounter();
  });

  describe('getPreferences', () => {
    it('should return undefined when no preferences exist', () => {
      expect(service.getPreferences('user-0001')).toBeUndefined();
    });

    it('should return preferences after they are created', () => {
      createTestUser(db);
      service.getOrCreatePreferences('user-0001');

      const prefs = service.getPreferences('user-0001');
      expect(prefs).toBeDefined();
      expect(prefs?.userId).toBe('user-0001');
    });
  });

  describe('getOrCreatePreferences', () => {
    it('should create default preferences for a user with all channels', () => {
      createTestUser(db);
      const prefs = service.getOrCreatePreferences('user-0001');

      expect(prefs.id).toBe('pref-0001');
      expect(prefs.userId).toBe('user-0001');
      // Email defaults
      expect(prefs.email.enabled).toBe(true);
      expect(prefs.email.frequency).toBe('immediate');
      expect(prefs.email.categories.order).toBe(true);
      expect(prefs.email.categories.user).toBe(true);
      // SMS defaults
      expect(prefs.sms.enabled).toBe(true);
      expect(prefs.sms.categories.order).toBe(true);
      expect(prefs.sms.categories.user).toBe(true);
      // Webhook defaults
      expect(prefs.webhook.enabled).toBe(true);
      expect(prefs.webhook.categories.order).toBe(true);
      expect(prefs.webhook.categories.user).toBe(true);
    });

    it('should return existing preferences without creating duplicates', () => {
      createTestUser(db);
      const first = service.getOrCreatePreferences('user-0001');
      const second = service.getOrCreatePreferences('user-0001');

      expect(first.id).toBe(second.id);
      expect(prefsRepo.count()).toBe(1);
    });

    it('should throw if user does not exist', () => {
      expect(() => service.getOrCreatePreferences('nonexistent')).toThrow(
        'User not found: nonexistent',
      );
    });

    it('should generate sequential IDs', () => {
      createTestUser(db, { id: 'user-0001' });
      createTestUser(db, { id: 'user-0002', email: 'bob@example.com' });

      const prefs1 = service.getOrCreatePreferences('user-0001');
      const prefs2 = service.getOrCreatePreferences('user-0002');

      expect(prefs1.id).toBe('pref-0001');
      expect(prefs2.id).toBe('pref-0002');
    });
  });

  describe('updatePreferences — email', () => {
    it('should disable email globally', () => {
      createTestUser(db);
      const updated = service.updatePreferences('user-0001', {
        email: { enabled: false },
      });

      expect(updated.email.enabled).toBe(false);
      // Other settings should remain at defaults
      expect(updated.email.frequency).toBe('immediate');
      expect(updated.email.categories.order).toBe(true);
    });

    it('should change email frequency', () => {
      createTestUser(db);
      const updated = service.updatePreferences('user-0001', {
        email: { frequency: 'daily-digest' },
      });

      expect(updated.email.frequency).toBe('daily-digest');
      expect(updated.email.enabled).toBe(true);
    });

    it('should update a single category without affecting others', () => {
      createTestUser(db);
      const updated = service.updatePreferences('user-0001', {
        email: { categories: { order: false } },
      });

      expect(updated.email.categories.order).toBe(false);
      expect(updated.email.categories.user).toBe(true);
    });

    it('should apply multiple changes at once', () => {
      createTestUser(db);
      const updated = service.updatePreferences('user-0001', {
        email: {
          frequency: 'none',
          categories: { order: false, user: false },
        },
      });

      expect(updated.email.frequency).toBe('none');
      expect(updated.email.categories.order).toBe(false);
      expect(updated.email.categories.user).toBe(false);
    });

    it('should create preferences if none exist before updating', () => {
      createTestUser(db);
      expect(service.getPreferences('user-0001')).toBeUndefined();

      const updated = service.updatePreferences('user-0001', {
        email: { categories: { order: false } },
      });

      expect(updated.email.categories.order).toBe(false);
      expect(updated.email.categories.user).toBe(true); // Default preserved
    });

    it('should throw if user does not exist', () => {
      expect(() =>
        service.updatePreferences('nonexistent', { email: { enabled: false } }),
      ).toThrow('User not found: nonexistent');
    });

    it('should persist changes across lookups', () => {
      createTestUser(db);
      service.updatePreferences('user-0001', {
        email: { enabled: false },
      });

      const retrieved = service.getPreferences('user-0001');
      expect(retrieved?.email.enabled).toBe(false);
    });
  });

  describe('updatePreferences — SMS', () => {
    it('should disable SMS globally', () => {
      createTestUser(db);
      const updated = service.updatePreferences('user-0001', {
        sms: { enabled: false },
      });

      expect(updated.sms.enabled).toBe(false);
      expect(updated.sms.categories.order).toBe(true);
      // Email should be unaffected
      expect(updated.email.enabled).toBe(true);
    });

    it('should disable SMS for a specific category', () => {
      createTestUser(db);
      const updated = service.updatePreferences('user-0001', {
        sms: { categories: { order: false } },
      });

      expect(updated.sms.categories.order).toBe(false);
      expect(updated.sms.categories.user).toBe(true);
    });
  });

  describe('updatePreferences — webhook', () => {
    it('should disable webhook globally', () => {
      createTestUser(db);
      const updated = service.updatePreferences('user-0001', {
        webhook: { enabled: false },
      });

      expect(updated.webhook.enabled).toBe(false);
      expect(updated.webhook.categories.order).toBe(true);
    });

    it('should disable webhook for a specific category', () => {
      createTestUser(db);
      const updated = service.updatePreferences('user-0001', {
        webhook: { categories: { user: false } },
      });

      expect(updated.webhook.categories.user).toBe(false);
      expect(updated.webhook.categories.order).toBe(true);
    });
  });

  describe('updatePreferences — multi-channel', () => {
    it('should update email and SMS together', () => {
      createTestUser(db);
      const updated = service.updatePreferences('user-0001', {
        email: { enabled: false },
        sms: { categories: { order: false } },
      });

      expect(updated.email.enabled).toBe(false);
      expect(updated.sms.categories.order).toBe(false);
      expect(updated.sms.enabled).toBe(true);
      expect(updated.webhook.enabled).toBe(true);
    });

    it('should update all three channels at once', () => {
      createTestUser(db);
      const updated = service.updatePreferences('user-0001', {
        email: { enabled: false },
        sms: { enabled: false },
        webhook: { enabled: false },
      });

      expect(updated.email.enabled).toBe(false);
      expect(updated.sms.enabled).toBe(false);
      expect(updated.webhook.enabled).toBe(false);
    });
  });

  describe('shouldSendEmail', () => {
    it('should return true when no preferences exist (opt-out model)', () => {
      expect(service.shouldSendEmail('user-0001', 'order:confirmation')).toBe(true);
    });

    it('should return true with default preferences', () => {
      createTestUser(db);
      service.getOrCreatePreferences('user-0001');

      expect(service.shouldSendEmail('user-0001', 'order:confirmation')).toBe(true);
      expect(service.shouldSendEmail('user-0001', 'order:status-update')).toBe(true);
      expect(service.shouldSendEmail('user-0001', 'user:welcome')).toBe(true);
      expect(service.shouldSendEmail('user-0001', 'user:profile-updated')).toBe(true);
    });

    it('should return false when email is globally disabled', () => {
      createTestUser(db);
      service.updatePreferences('user-0001', { email: { enabled: false } });

      expect(service.shouldSendEmail('user-0001', 'order:confirmation')).toBe(false);
      expect(service.shouldSendEmail('user-0001', 'user:welcome')).toBe(false);
    });

    it('should return false when frequency is none', () => {
      createTestUser(db);
      service.updatePreferences('user-0001', { email: { frequency: 'none' } });

      expect(service.shouldSendEmail('user-0001', 'order:confirmation')).toBe(false);
    });

    it('should return true when frequency is daily-digest', () => {
      createTestUser(db);
      service.updatePreferences('user-0001', { email: { frequency: 'daily-digest' } });

      expect(service.shouldSendEmail('user-0001', 'order:confirmation')).toBe(true);
    });

    it('should return false for a disabled category', () => {
      createTestUser(db);
      service.updatePreferences('user-0001', {
        email: { categories: { order: false } },
      });

      expect(service.shouldSendEmail('user-0001', 'order:confirmation')).toBe(false);
      expect(service.shouldSendEmail('user-0001', 'order:status-update')).toBe(false);
      // User category should still be enabled
      expect(service.shouldSendEmail('user-0001', 'user:welcome')).toBe(true);
    });

    it('should respect category-level settings independently', () => {
      createTestUser(db);
      service.updatePreferences('user-0001', {
        email: { categories: { user: false } },
      });

      expect(service.shouldSendEmail('user-0001', 'order:confirmation')).toBe(true);
      expect(service.shouldSendEmail('user-0001', 'user:welcome')).toBe(false);
      expect(service.shouldSendEmail('user-0001', 'user:profile-updated')).toBe(false);
    });
  });

  describe('shouldSendSms', () => {
    it('should return true when no preferences exist (opt-out model)', () => {
      expect(service.shouldSendSms('user-0001', 'order:confirmation')).toBe(true);
    });

    it('should return true with default preferences', () => {
      createTestUser(db);
      service.getOrCreatePreferences('user-0001');

      expect(service.shouldSendSms('user-0001', 'order:confirmation')).toBe(true);
      expect(service.shouldSendSms('user-0001', 'user:welcome')).toBe(true);
    });

    it('should return false when SMS is globally disabled', () => {
      createTestUser(db);
      service.updatePreferences('user-0001', { sms: { enabled: false } });

      expect(service.shouldSendSms('user-0001', 'order:confirmation')).toBe(false);
      expect(service.shouldSendSms('user-0001', 'user:welcome')).toBe(false);
    });

    it('should return false for a disabled category', () => {
      createTestUser(db);
      service.updatePreferences('user-0001', {
        sms: { categories: { order: false } },
      });

      expect(service.shouldSendSms('user-0001', 'order:confirmation')).toBe(false);
      expect(service.shouldSendSms('user-0001', 'user:welcome')).toBe(true);
    });

    it('should be independent of email preferences', () => {
      createTestUser(db);
      service.updatePreferences('user-0001', {
        email: { enabled: false },
      });

      // Email disabled doesn't affect SMS
      expect(service.shouldSendSms('user-0001', 'order:confirmation')).toBe(true);
    });
  });

  describe('shouldSendWebhook', () => {
    it('should return true when no preferences exist', () => {
      expect(service.shouldSendWebhook('user-0001', 'order:confirmation')).toBe(true);
    });

    it('should return false when webhook is globally disabled', () => {
      createTestUser(db);
      service.updatePreferences('user-0001', { webhook: { enabled: false } });

      expect(service.shouldSendWebhook('user-0001', 'order:confirmation')).toBe(false);
    });

    it('should return false for a disabled category', () => {
      createTestUser(db);
      service.updatePreferences('user-0001', {
        webhook: { categories: { user: false } },
      });

      expect(service.shouldSendWebhook('user-0001', 'user:welcome')).toBe(false);
      expect(service.shouldSendWebhook('user-0001', 'order:confirmation')).toBe(true);
    });
  });

  describe('shouldSend (generic)', () => {
    it('should work for any supported channel', () => {
      createTestUser(db);
      service.updatePreferences('user-0001', {
        email: { enabled: false },
        sms: { categories: { order: false } },
      });

      expect(service.shouldSend('email', 'user-0001', 'order:confirmation')).toBe(false);
      expect(service.shouldSend('sms', 'user-0001', 'order:confirmation')).toBe(false);
      expect(service.shouldSend('sms', 'user-0001', 'user:welcome')).toBe(true);
      expect(service.shouldSend('webhook', 'user-0001', 'order:confirmation')).toBe(true);
    });
  });

  describe('NotificationService integration', () => {
    it('should suppress email when user has opted out of order category', async () => {
      createTestUser(db);
      service.updatePreferences('user-0001', {
        email: { categories: { order: false } },
      });

      const eventBus = new EventBus();
      const notifService = new NotificationService(eventBus);
      const emailAdapter = new EmailAdapter();
      notifService.registerAdapter(emailAdapter);
      notifService.setPreferencesService(service);
      resetNotificationIdCounter();

      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-0001',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      // Email suppressed, but webhook still sent (webhook order category is enabled by default)
      expect(emailAdapter.getSentEmails()).toHaveLength(0);
      const notifications = notifService.getNotifications();
      const emailNotifs = notifications.filter((n) => n.channel === 'email');
      const webhookNotifs = notifications.filter((n) => n.channel === 'webhook');
      expect(emailNotifs).toHaveLength(0);
      expect(webhookNotifs).toHaveLength(1);
    });

    it('should send all channels with default preferences', async () => {
      createTestUser(db);
      service.getOrCreatePreferences('user-0001');

      const eventBus = new EventBus();
      const notifService = new NotificationService(eventBus);
      const emailAdapter = new EmailAdapter();
      notifService.registerAdapter(emailAdapter);
