          items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-0001',
          name: 'Alice',
          email: 'alice@example.com',
          phone: '+15551234567',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      // email + SMS + webhook = 3
      expect(notifService.getNotificationCount()).toBe(3);
      expect(emailAdapter.getSentEmails()).toHaveLength(1);
      expect(smsAdapter.getSentMessages()).toHaveLength(1);
      expect(smsAdapter.getSentMessages()[0]?.to).toBe('+15551234567');
    });

    it('should suppress SMS when SMS disabled but still send email', async () => {
      createTestUser(db);
      service.updatePreferences('user-0001', {
        sms: { enabled: false },
      });

      const eventBus = new EventBus();
      const notifService = new NotificationService(eventBus);
      const emailAdapter = new EmailAdapter();
      const smsAdapter = new SmsAdapter({ fromNumber: '+15550000000' });
      notifService.registerAdapter(emailAdapter);
      notifService.registerAdapter(smsAdapter);
      notifService.setPreferencesService(service);
      resetNotificationIdCounter();

      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-0001',
          name: 'Alice',
          email: 'alice@example.com',
          phone: '+15551234567',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      // SMS suppressed, email + webhook sent
      expect(emailAdapter.getSentEmails()).toHaveLength(1);
      expect(smsAdapter.getSentMessages()).toHaveLength(0);
      expect(notifService.getNotificationCount()).toBe(2);
    });
  });
});

import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { NotificationLogRepository } from '../../src/repositories/notification-log.repository.js';
import {
  NotificationHistoryService,
  resetNotificationLogIdCounter,
} from '../../src/services/notification-history.service.js';
import { EventBus } from '../../src/events/event-bus.js';
import {
  NotificationService,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import { EmailAdapter } from '../../src/adapters/email.adapter.js';
import type { NotificationPayload } from '../../src/models/notification.js';
import type { NotificationAdapter } from '../../src/adapters/notification.adapter.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../../src/events/event-types.js';

describe('NotificationHistoryService', () => {
  let db: Database;
  let repository: NotificationLogRepository;
  let historyService: NotificationHistoryService;

  beforeEach(() => {
    db = new Database();
    repository = new NotificationLogRepository(db);
    historyService = new NotificationHistoryService(repository);
    resetNotificationLogIdCounter();
  });

  const basePayload: NotificationPayload = {
    recipient: 'alice@example.com',
    subject: 'Order Confirmation: order-1',
    body: 'Your order has been placed.',
    channel: 'email',
    type: 'order:confirmation',
  };

  describe('log', () => {
    it('should log a sent notification', async () => {
      const entry = await historyService.log(basePayload, 'sent');

      expect(entry.id).toBe('nlog-0001');
      expect(entry.recipient).toBe('alice@example.com');
      expect(entry.channel).toBe('email');
      expect(entry.type).toBe('order:confirmation');
      expect(entry.subject).toBe('Order Confirmation: order-1');
      expect(entry.body).toBe('Your order has been placed.');
      expect(entry.status).toBe('sent');
      expect(entry.timestamp).toBeInstanceOf(Date);
      expect(entry.error).toBeUndefined();
    });

    it('should log a failed notification with error', async () => {
      const entry = await historyService.log(basePayload, 'failed', 'SMTP timeout');

      expect(entry.status).toBe('failed');
      expect(entry.error).toBe('SMTP timeout');
    });

    it('should log a suppressed notification', async () => {
      const entry = await historyService.log(basePayload, 'suppressed');

      expect(entry.status).toBe('suppressed');
    });

    it('should generate sequential IDs', async () => {
      const entry1 = await historyService.log(basePayload, 'sent');
      const entry2 = await historyService.log(basePayload, 'sent');
      const entry3 = await historyService.log(basePayload, 'sent');

      expect(entry1.id).toBe('nlog-0001');
      expect(entry2.id).toBe('nlog-0002');
      expect(entry3.id).toBe('nlog-0003');
    });

    it('should preserve metadata from payload', async () => {
      const payloadWithMeta: NotificationPayload = {
        ...basePayload,
        metadata: { orderId: 'order-1', priority: 'high' },
      };

      const entry = await historyService.log(payloadWithMeta, 'sent');

      expect(entry.metadata).toEqual({ orderId: 'order-1', priority: 'high' });
    });

    it('should persist entries to the repository', async () => {
      await historyService.log(basePayload, 'sent');

      expect(repository.count()).toBe(1);
      const stored = repository.findById('nlog-0001');
      expect(stored).toBeDefined();
      expect(stored!.recipient).toBe('alice@example.com');
    });
  });

  describe('queryHistory', () => {
    beforeEach(async () => {
      await historyService.log(
        { ...basePayload, recipient: 'alice@example.com', channel: 'email', type: 'order:confirmation' },
        'sent',
      );
      await historyService.log(
        { ...basePayload, recipient: 'bob@example.com', channel: 'webhook', type: 'order:status-update' },
        'failed',
        'Connection refused',
      );
      await historyService.log(
        { ...basePayload, recipient: 'alice@example.com', channel: 'email', type: 'user:welcome' },
        'suppressed',
      );
    });

    it('should return all entries with empty query', () => {
      const results = historyService.queryHistory({});
      expect(results).toHaveLength(3);
    });

    it('should filter by recipient', () => {
      const results = historyService.queryHistory({ recipient: 'alice@example.com' });
      expect(results).toHaveLength(2);
      expect(results.every((e) => e.recipient === 'alice@example.com')).toBe(true);
    });

    it('should filter by channel', () => {
      const results = historyService.queryHistory({ channel: 'webhook' });
      expect(results).toHaveLength(1);
      expect(results[0]!.channel).toBe('webhook');
    });

    it('should filter by type', () => {
      const results = historyService.queryHistory({ type: 'order:confirmation' });
      expect(results).toHaveLength(1);
      expect(results[0]!.type).toBe('order:confirmation');
    });

    it('should filter by status', () => {
      const results = historyService.queryHistory({ status: 'failed' });
      expect(results).toHaveLength(1);
      expect(results[0]!.status).toBe('failed');
    });

    it('should combine multiple filters', () => {
      const results = historyService.queryHistory({
        recipient: 'alice@example.com',
        channel: 'email',
        status: 'sent',
      });
      expect(results).toHaveLength(1);
      expect(results[0]!.type).toBe('order:confirmation');
    });

    it('should return empty array when no entries match', () => {
      const results = historyService.queryHistory({ recipient: 'charlie@example.com' });
      expect(results).toHaveLength(0);
    });
  });

  describe('queryHistory — date range', () => {
    it('should filter by date range', async () => {
      const now = new Date();
      const yesterday = new Date(now.getTime() - 86400000);
      const tomorrow = new Date(now.getTime() + 86400000);

      await historyService.log(basePayload, 'sent');

      const inRange = historyService.queryHistory({ startDate: yesterday, endDate: tomorrow });
      expect(inRange).toHaveLength(1);

      const outOfRange = historyService.queryHistory({
        startDate: new Date('2020-01-01'),
        endDate: new Date('2020-01-02'),
      });
      expect(outOfRange).toHaveLength(0);
    });
  });

  describe('getHistoryForRecipient', () => {
    it('should return entries for a specific recipient', async () => {
      await historyService.log(basePayload, 'sent');
      await historyService.log({ ...basePayload, recipient: 'bob@example.com' }, 'sent');

      const aliceHistory = historyService.getHistoryForRecipient('alice@example.com');
      expect(aliceHistory).toHaveLength(1);
      expect(aliceHistory[0]!.recipient).toBe('alice@example.com');
    });

    it('should return empty array for unknown recipient', () => {
      const results = historyService.getHistoryForRecipient('nobody@example.com');
      expect(results).toHaveLength(0);
    });
  });

  describe('getHistoryByType', () => {
    it('should return entries of a specific type', async () => {
      await historyService.log(basePayload, 'sent');
      await historyService.log({ ...basePayload, type: 'user:welcome' }, 'sent');

      const results = historyService.getHistoryByType('order:confirmation');
      expect(results).toHaveLength(1);
      expect(results[0]!.type).toBe('order:confirmation');
    });

    it('should return empty array for undefined type', () => {
      const results = historyService.getHistoryByType(undefined);
      expect(results).toHaveLength(0);
    });
  });

  describe('getHistoryByDateRange', () => {
    it('should return entries within the date range', async () => {
      await historyService.log(basePayload, 'sent');

      const now = new Date();
      const results = historyService.getHistoryByDateRange(
        new Date(now.getTime() - 60000),
        new Date(now.getTime() + 60000),
      );
      expect(results).toHaveLength(1);
    });
  });

  describe('getLogCount', () => {
    it('should return 0 when no entries exist', () => {
      expect(historyService.getLogCount()).toBe(0);
    });

    it('should return the correct count', async () => {
      await historyService.log(basePayload, 'sent');
      await historyService.log(basePayload, 'failed', 'error');

      expect(historyService.getLogCount()).toBe(2);
    });
  });

  describe('getAllHistory', () => {
    it('should return all entries', async () => {
      await historyService.log(basePayload, 'sent');
      await historyService.log(basePayload, 'failed', 'error');

      const all = historyService.getAllHistory();
      expect(all).toHaveLength(2);
    });
  });

  describe('Integration with NotificationService', () => {
    let eventBus: EventBus;
    let notificationService: NotificationService;
    let emailAdapter: EmailAdapter;

    beforeEach(() => {
      eventBus = new EventBus();
      notificationService = new NotificationService(eventBus);
      emailAdapter = new EmailAdapter();
      notificationService.registerAdapter(emailAdapter);
      notificationService.setHistoryService(historyService);
      resetNotificationIdCounter();
    });

    it('should log sent notifications via event flow (multi-channel)', async () => {
      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      // email + webhook = 2 log entries (no phone = no SMS)
      const history = historyService.getAllHistory();
      expect(history).toHaveLength(2);

      const emailLog = history.find((h) => h.channel === 'email');
      expect(emailLog).toBeDefined();
      expect(emailLog!.recipient).toBe('alice@example.com');
      expect(emailLog!.type).toBe('order:confirmation');
      expect(emailLog!.status).toBe('sent');

      const webhookLog = history.find((h) => h.channel === 'webhook');
      expect(webhookLog).toBeDefined();
      expect(webhookLog!.type).toBe('order:confirmation');
      // No webhook adapter registered, so logged as 'sent' (no adapter = still recorded)
      expect(webhookLog!.status).toBe('sent');
    });

    it('should log failed notifications when adapter throws', async () => {
      const failingAdapter: NotificationAdapter = {
        channel: 'email',
        async send() {
          throw new Error('SMTP connection failed');
        },
      };
      notificationService.registerAdapter(failingAdapter);

      const event: OrderStatusChangedEvent = {
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      // email (failed) + webhook (no adapter, 'sent') = 2 entries
      const history = historyService.getAllHistory();
      expect(history).toHaveLength(2);

      const emailLog = history.find((h) => h.channel === 'email');
      expect(emailLog!.status).toBe('failed');
      expect(emailLog!.error).toBe('SMTP connection failed');
    });

    it('should log notifications when no adapter is registered', async () => {
      const localBus = new EventBus();
      const bareService = new NotificationService(localBus);
      bareService.setHistoryService(historyService);

      const event: OrderStatusChangedEvent = {
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      };

      await localBus.emit(event);

      // email + webhook = 2 entries, both 'sent' (no adapter doesn't mean failure)
      const history = historyService.getAllHistory();
      expect(history).toHaveLength(2);
      expect(history.every((h) => h.status === 'sent')).toBe(true);
    });

    it('should work without history service (backwards compatible)', async () => {
      const localBus = new EventBus();
      const serviceWithoutHistory = new NotificationService(localBus);
      serviceWithoutHistory.registerAdapter(new EmailAdapter());
      // No history service set

      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      // Should not throw
      await localBus.emit(event);

      // email + webhook = 2
      expect(serviceWithoutHistory.getNotificationCount()).toBe(2);
    });

    it('should log multiple notifications across different events and channels', async () => {
      const orderCreatedEvent: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      const statusChangedEvent: OrderStatusChangedEvent = {
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 10,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      };

      await eventBus.emit(orderCreatedEvent);
      await eventBus.emit(statusChangedEvent);

      // order:created => email + webhook = 2
      // order:status-changed => email + webhook = 2
      // total = 4
      const history = historyService.getAllHistory();
      expect(history).toHaveLength(4);

      const confirmations = history.filter((h) => h.type === 'order:confirmation');
      const updates = history.filter((h) => h.type === 'order:status-update');
      expect(confirmations).toHaveLength(2);
      expect(updates).toHaveLength(2);
    });
  });
});
